const html = $input.first().json.data;

// Strip all HTML tags
let text = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');

// Clean up whitespace
text = text.replace(/\s+/g, ' ').trim();

// Trim to ~12,000 chars to fit in AI context window
text = text.substring(0, 12000);

return [{ json: { cleanText: text } }];

const response = $input.first().json;
const rawText = response.content[0].text;
const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const assessment = JSON.parse(cleaned);
return [{ json: assessment }];

// n8n Code Node — Generate 8-bit HTML Privacy Assessment Report
// Place this in a Code node after "Parse Assessment JSON"
// Node name: 🎮 Generate HTML Report

const data = $('📊 Parse Assessment JSON').first().json;

const riskColor = {
  'HIGH': '#ff4444',
  'MEDIUM': '#ffaa00', 
  'LOW': '#00ff88'
};

const riskBg = {
  'HIGH': '#2a0000',
  'MEDIUM': '#2a1a00',
  'LOW': '#002a1a'
};

const scoreBar = (score) => {
  const filled = score;
  const empty = 5 - score;
  return '█'.repeat(filled) + '░'.repeat(empty);
};

const scoreColor = (score) => {
  if (score <= 1) return '#ff4444';
  if (score <= 2) return '#ff8800';
  if (score <= 3) return '#ffdd00';
  return '#00ff88';
};

const dimensionLabels = {
  D1_data_minimization: 'D1 · DATA MINIMIZATION',
  D2_sub_processor: 'D2 · SUB-PROCESSORS',
  D3_subject_rights: 'D3 · SUBJECT RIGHTS',
  D4_transfer_mechanisms: 'D4 · TRANSFER MECHANISMS',
  D5_breach_notification: 'D5 · BREACH NOTIFICATION',
  D6_ai_ml_usage: 'D6 · AI/ML DATA USAGE ★',
  D7_retention_deletion: 'D7 · RETENTION & DELETION',
  D8_dpa_completeness: 'D8 · DPA COMPLETENESS ★'
};

const scoresHTML = Object.entries(data.scores || {}).map(([key, val]) => {
  const label = dimensionLabels[key] || key;
  const score = val.score;
  const rationale = val.rationale || '';
  const redFlags = (val.red_flags || []).map(f => `<li>⚠ ${f}</li>`).join('');

  return `
    <div class="dimension-card" style="border-color: ${scoreColor(score)}">
      <div class="dim-header">
        <span class="dim-label">${label}</span>
        <span class="dim-score" style="color: ${scoreColor(score)}">${scoreBar(score)} ${score}/5</span>
      </div>
      <div class="dim-rationale">${rationale}</div>
      ${redFlags ? `<ul class="red-flags">${redFlags}</ul>` : ''}
    </div>
  `;
}).join('');

const top3HTML = (data.top_3_findings || []).map((f, i) => 
  `<div class="finding">▶ ${f}</div>`
).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Privacy Assessment — ${data.vendor}</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Press+Start+2P&family=Share+Tech+Mono&display=swap');

  :root {
    --bg: #0a0a0f;
    --panel: #12121a;
    --border: #2a2a3a;
    --text: #c8c8e8;
    --dim: #6060a0;
    --accent: #7700ff;
    --risk: ${riskColor[data.risk_tier] || '#ffaa00'};
    --risk-bg: ${riskBg[data.risk_tier] || '#2a1a00'};
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: 'Share Tech Mono', monospace;
    font-size: 13px;
    line-height: 1.6;
    padding: 32px 24px;
    max-width: 900px;
    margin: 0 auto;
  }

  /* Scanline overlay */
  body::before {
    content: '';
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      rgba(0,0,0,0.15) 2px,
      rgba(0,0,0,0.15) 4px
    );
    pointer-events: none;
    z-index: 999;
  }

  .header {
    text-align: center;
    border: 3px solid var(--accent);
    padding: 24px;
    margin-bottom: 32px;
    position: relative;
    background: #0d0d18;
    image-rendering: pixelated;
  }

  .header::before {
    content: '◄ THE PRIVACY LENS ►';
    display: block;
    font-family: 'Press Start 2P', monospace;
    font-size: 9px;
    color: var(--accent);
    margin-bottom: 16px;
    letter-spacing: 2px;
  }

  .vendor-name {
    font-family: 'Press Start 2P', monospace;
    font-size: 18px;
    color: #ffffff;
    margin-bottom: 8px;
    text-shadow: 0 0 20px var(--accent);
  }

  .assessment-date {
    color: var(--dim);
    font-size: 11px;
  }

  .risk-banner {
    background: var(--risk-bg);
    border: 3px solid var(--risk);
    padding: 20px 24px;
    margin-bottom: 24px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    animation: pulse 2s infinite;
  }

  @keyframes pulse {
    0%, 100% { box-shadow: 0 0 8px var(--risk); }
    50% { box-shadow: 0 0 24px var(--risk); }
  }

  .risk-label {
    font-family: 'Press Start 2P', monospace;
    font-size: 10px;
    color: var(--dim);
  }

  .risk-tier {
    font-family: 'Press Start 2P', monospace;
    font-size: 22px;
    color: var(--risk);
    text-shadow: 0 0 16px var(--risk);
  }

  .risk-score {
    font-family: 'Press Start 2P', monospace;
    font-size: 14px;
    color: var(--risk);
    text-align: right;
  }

  .badges {
    display: flex;
    gap: 12px;
    margin-bottom: 24px;
    flex-wrap: wrap;
  }

  .badge {
    border: 2px solid;
    padding: 6px 12px;
    font-size: 11px;
    font-family: 'Press Start 2P', monospace;
    font-size: 8px;
  }

  .badge.ai { border-color: #ff00ff; color: #ff00ff; background: #1a001a; }
  .badge.no-ai { border-color: #404060; color: #404060; background: #0d0d18; }
  .badge.ai-risk { border-color: #ff4444; color: #ff4444; background: #1a0000; }

  .section {
    border: 2px solid var(--border);
    margin-bottom: 20px;
    background: var(--panel);
  }

  .section-header {
    background: var(--border);
    padding: 10px 16px;
    font-family: 'Press Start 2P', monospace;
    font-size: 9px;
    color: var(--accent);
    letter-spacing: 1px;
  }

  .section-body {
    padding: 16px;
  }

  .finding {
    padding: 8px 0;
    border-bottom: 1px solid var(--border);
    color: #ffcc00;
    font-size: 12px;
  }

  .finding:last-child { border-bottom: none; }

  .dimension-card {
    border: 2px solid;
    margin-bottom: 12px;
    background: #0d0d18;
    padding: 14px 16px;
  }

  .dim-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 8px;
    flex-wrap: wrap;
    gap: 8px;
  }

  .dim-label {
    font-family: 'Press Start 2P', monospace;
    font-size: 8px;
    color: #aaaacc;
  }

  .dim-score {
    font-family: 'Press Start 2P', monospace;
    font-size: 9px;
    white-space: nowrap;
  }

  .dim-rationale {
    color: #8888aa;
    font-size: 12px;
    margin-bottom: 8px;
  }

  .red-flags {
    list-style: none;
    padding: 0;
  }

  .red-flags li {
    color: #ff6644;
    font-size: 11px;
    padding: 2px 0;
  }

  .footer {
    text-align: center;
    margin-top: 32px;
    color: var(--dim);
    font-size: 10px;
    border-top: 2px solid var(--border);
    padding-top: 16px;
    font-family: 'Press Start 2P', monospace;
    font-size: 7px;
    line-height: 2;
  }

  .pixel-divider {
    text-align: center;
    color: var(--accent);
    margin: 8px 0;
    font-size: 10px;
    letter-spacing: 4px;
  }
</style>
</head>
<body>

<div class="header">
  <div class="vendor-name">${data.vendor || 'UNKNOWN VENDOR'}</div>
  <div class="assessment-date">ASSESSMENT DATE: ${data.assessment_date || 'N/A'}</div>
</div>

<div class="risk-banner">
  <div>
    <div class="risk-label">RISK TIER</div>
    <div class="risk-tier">${data.risk_tier || 'UNKNOWN'}</div>
  </div>
  <div style="text-align:right">
    <div class="risk-label">WEIGHTED AVG</div>
    <div class="risk-score">${data.weighted_average || 'N/A'} / 5</div>
  </div>
</div>

<div class="badges">
  ${data.is_ai_vendor 
    ? '<div class="badge ai">⚡ AI VENDOR DETECTED</div>' 
    : '<div class="badge no-ai">○ NOT AI VENDOR</div>'}
  ${data.ai_training_risk 
    ? '<div class="badge ai-risk">⚠ AI TRAINING RISK</div>' 
    : ''}
</div>

<div class="section">
  <div class="section-header">▶ TOP FINDINGS</div>
  <div class="section-body">
    ${top3HTML || '<div class="finding">No findings recorded.</div>'}
  </div>
</div>

<div class="section">
  <div class="section-header">▶ DIMENSION SCORES</div>
  <div class="section-body">
    ${scoresHTML || '<div>No scores available.</div>'}
  </div>
</div>

<div class="pixel-divider">· · · · · · · · · · · · · · · · · · · ·</div>

<div class="footer">
  GENERATED BY THE PRIVACY LENS · PHASE 1<br>
  OPEN SOURCE TPRM AUTOMATION · github.com/conorrusso/privacy-risk-analyzer<br>
  ${new Date().toISOString()}
</div>

</body>
</html>`;

const htmlBuffer = Buffer.from(html, 'utf8');

return [{ 
  json: { 
    vendor: data.vendor,
    assessment_date: data.assessment_date,
    risk_tier: data.risk_tier
  },
  binary: {
    htmlFile: {
      data: htmlBuffer.toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
